mapper.select:
select p.id, p.name, p.brand, p.model, p.category_id, p.price, p.stock,
       p.image, p.status, p.update_time, c.name as category_name
from product p
left join category c on p.category_id = c.id

    inner join product_phone_model ppm on p.id = ppm.product_id



        and p.name like concat('%',#{name},'%')


        and p.category_id = #{categoryId}


        and p.status = #{status}


        and ppm.phone_model_id = #{phoneModelId}


order by p.update_time desc
